commands.cmd:
raw=$(chronyc tracking) || { echo "chronyc tracking failed" >&2; exit 1; }
printf '%s\n' "$raw" | awk '
  /^Last offset/ { off=$4 }
  /^Leap status/ { sub(/^Leap status[ ]*:[ ]*/, ""); leap=$0 }
  /^Reference ID/ { synced=($0 ~ /00000000/) ? "false" : "true" }
  END{
    if (off=="") { print "Last offset missing" > "/dev/stderr"; exit 1 }
    abs=(off<0)?-off:off
    printf "{\"offset_seconds\":%.9f,\"abs_offset_seconds\":%.9f,\"leap_status\":\"%s\",\"synced\":%s}",
      off, abs, leap, (synced==""?"true":synced)
  }' || exit 1
